type Query {
    ${queryField}: String @resolver(class: "${vendor}\\${module}\\Model\\Resolver\\${resolver}") @doc(description: "${queryField}")
}

{
  "name": "${vendor}/module-${module}",
  "description": "${vendor}_${module} module",
  "type": "magento2-module",
  "license": "OSL-3.0",
  "require": {
    "php": "~8.3.0||~8.4.0"
  },
  "autoload": {
    "files": ["registration.php"],
    "psr-4": { "${vendor}\\${module}\\": "" }
  }
}
